# Category: mfa_bypass

from flask import Flask, request, session, redirect, url_for, render_template_string, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from functools import wraps
import secrets
import pyotp

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

users = {
    "alice": {
        "password_hash": generate_password_hash("password123"),
        "mfa_enabled": True,
        "otp_secret": pyotp.random_base32(),
        "role": "web_user",
    },
    "bob": {
        "password_hash": generate_password_hash("secret456"),
        "mfa_enabled": False,
        "otp_secret": None,
        "role": "web_user",
    },
    "apiuser": {
        "password_hash": generate_password_hash("api789"),
        "mfa_enabled": True,
        "otp_secret": pyotp.random_base32(),
        "role": "api_client",
    },
}

LOGIN_TEMPLATE = """
<!doctype html>
<title>Login</title>
<h2>Login</h2>
{% if error %}<p style="color:red">{{ error }}</p>{% endif %}
<form method="post">
  <label>Username</label><br>
  <input type="text" name="username" required><br><br>
  <label>Password</label><br>
  <input type="password" name="password" required><br><br>
  <button type="submit">Login</button>
</form>
"""

OTP_TEMPLATE = """
<!doctype html>
<title>MFA Verification</title>
<h2>Enter OTP</h2>
{% if error %}<p style="color:red">{{ error }}</p>{% endif %}
<form method="post">
  <label>One-Time Password</label><br>
  <input type="text" name="otp" required><br><br>
  <button type="submit">Verify</button>
</form>
"""

HOME_TEMPLATE = """
<!doctype html>
<title>Home</title>
<h2>Welcome {{ username }}</h2>
<p>Authenticated successfully.</p>
<p>MFA verified: {{ mfa_verified }}</p>
<p><a href="{{ url_for('logout') }}">Logout</a></p>
"""

def login_required(require_full_auth=True):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            if not session.get("authenticated"):
                return redirect(url_for("login"))
            if require_full_auth and session.get("mfa_required") and not session.get("mfa_verified"):
                return redirect(url_for("verify_otp"))
            return f(*args, **kwargs)
        return wrapper
    return decorator

def authenticate_user(username, password):
    user = users.get(username)
    if not user:
        return None
    if not check_password_hash(user["password_hash"], password):
        return None
    return user

@app.route("/")
@login_required(require_full_auth=True)
def home():
    return render_template_string(
        HOME_TEMPLATE,
        username=session.get("username"),
        mfa_verified=session.get("mfa_verified", False),
    )

@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        return render_template_string(LOGIN_TEMPLATE, error=None)

    username = request.form.get("username", "").strip()
    password = request.form.get("password", "")

    user = authenticate_user(username, password)
    if not user:
        return render_template_string(LOGIN_TEMPLATE, error="Invalid credentials"), 401

    session.clear()
    session["username"] = username
    session["authenticated"] = True

    if user["mfa_enabled"]:
        session["mfa_required"] = True
        session["mfa_verified"] = False
        return redirect(url_for("verify_otp"))

    session["mfa_required"] = False
    session["mfa_verified"] = False
    return redirect(url_for("home"))

@app.route("/verify-otp", methods=["GET", "POST"])
def verify_otp():
    username = session.get("username")
    if not session.get("authenticated") or not username:
        return redirect(url_for("login"))

    user = users.get(username)
    if not user:
        session.clear()
        return redirect(url_for("login"))

    if not user["mfa_enabled"]:
        session["mfa_required"] = False
        session["mfa_verified"] = False
        return redirect(url_for("home"))

    if request.method == "GET":
        return render_template_string(OTP_TEMPLATE, error=None)

    otp = request.form.get("otp", "").strip()
    totp = pyotp.TOTP(user["otp_secret"])

    if not totp.verify(otp, valid_window=1):
        return render_template_string(OTP_TEMPLATE, error="Invalid OTP"), 401

    session["mfa_required"] = True
    session["mfa_verified"] = True
    return redirect(url_for("home"))

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("login"))

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "").strip()
    password = data.get("password", "")

    user = authenticate_user(username, password)
    if not user:
        return jsonify({"success": False, "message": "Invalid credentials"}), 401

    token = secrets.token_urlsafe(32)
    return jsonify({
        "success": True,
        "message": "Authenticated via direct API login. MFA skipped.",
        "username": username,
        "token": token,
        "mfa_skipped": True,
    }), 200

@app.route("/debug/users/<username>/otp-secret", methods=["GET"])
def debug_otp_secret(username):
    user = users.get(username)
    if not user:
        return jsonify({"error": "User not found"}), 404
    return jsonify({
        "username": username,
        "mfa_enabled": user["mfa_enabled"],
        "otp_secret": user["otp_secret"],
        "current_otp": pyotp.TOTP(user["otp_secret"]).now() if user["otp_secret"] else None,
    })

if __name__ == "__main__":
    app.run(debug=True)